const languages = ["en", "hi", "mr", "te", "kn", "ta", "bn", "gu", "or"];

languages.forEach(lang => {
  const translations = {};
  
  // Transform baseTranslation entries to lang specific entries
  Object.keys(baseTranslation).forEach(key => {
    const parts = key.split('.');
    let current = translations;
    
    for (let i = 0; i < parts.length - 1; i++) {
      if (!current[parts[i]]) {
        current[parts[i]] = {};
      }
      current = current[parts[i]];
    }
    
    const lastKey = parts[parts.length - 1];
    current[lastKey] = baseTranslation[key][lang] || baseTranslation[key]['en'];
  });
  
  const destDir = path.join(__dirname, 'frontend', 'public', 'locales', lang);
  if (!fs.existsSync(destDir)) {
    fs.mkdirSync(destDir, { recursive: true });
  }
  
  const destFile = path.join(destDir, 'translation.json');
  fs.writeFileSync(destFile, JSON.stringify(translations, null, 2), 'utf8');
  console.log(`Wrote translations for ${lang} to ${destFile}`);
});
